// Extrair contexto do orquestrador para decisões de roteamento
const input = $input.first().json.body;
const orchestrator = input.orchestrator || {};

console.log('Tool usada:', orchestrator.source_tool);
console.log('Argumentos originais:', JSON.stringify(orchestrator.tool_arguments));
console.log('Tools disponíveis:', orchestrator.available_tools);

// Preparar dados para roteamento
return {
  event: input.event,
  report: input.report,
  user: input.user,
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  // Contexto do orquestrador
  source_tool: orchestrator.source_tool,
  tool_arguments: orchestrator.tool_arguments,
  tool_metadata: orchestrator.tool_metadata,
  available_tools: orchestrator.available_tools
};

// Agente de Análise de Relatos Urbanos
// Usa tool_arguments para acessar dados originais inferidos pelo LLM

const input = $input.first().json;
const report = input.report;
const toolArgs = input.tool_arguments || {};

// Descrição pode vir do report ou dos argumentos originais da tool
const description = (toolArgs.description || report.description || '').toLowerCase();

// Classificação de prioridade baseada em análise de conteúdo
let priority = 'normal';
let severity = 'media';
let tags = [];

// Detecção de urgência por palavras-chave
const urgentKeywords = ['urgente', 'perigo', 'risco', 'acidente', 'vazamento', 'desabamento', 'incêndio', 'criança', 'idoso'];
const highKeywords = ['buraco', 'cratera', 'alagamento', 'queda', 'sem luz', 'falta água', 'esgoto', 'entupido'];

if (urgentKeywords.some(k => description.includes(k))) {
  priority = 'urgente';
  severity = 'critica';
  tags.push('ATENÇÃO_IMEDIATA');
} else if (highKeywords.some(k => description.includes(k))) {
  priority = 'alta';
  severity = 'alta';
}

// Categorização automática refinada
const categoryMap = {
  'buraco': 'infraestrutura',
  'iluminação': 'iluminacao_publica',
  'poste': 'iluminacao_publica',
  'luz': 'iluminacao_publica',
  'lixo': 'limpeza_urbana',
  'entulho': 'limpeza_urbana',
  'esgoto': 'saneamento',
  'água': 'saneamento',
  'árvore': 'meio_ambiente',
  'poda': 'meio_ambiente',
  'calçada': 'acessibilidade',
  'rampa': 'acessibilidade',
  'sinal': 'sinalizacao',
  'semáforo': 'sinalizacao'
};

let validatedCategory = toolArgs.category || report.category || 'outro';
for (const [keyword, cat] of Object.entries(categoryMap)) {
  if (description.includes(keyword)) {
    validatedCategory = cat;
    tags.push(`AUTO_${cat.toUpperCase()}`);
    break;
  }
}

// Enriquecimento com dados contextuais
const enrichedData = {
  bairro_normalizado: (toolArgs.location_address || report.location_address || '').split(',')[1]?.trim() || null,
  coordenadas_validas: !!(report.latitude && report.longitude),
  tem_fotos: (report.photos?.length || 0) > 0,
  hora_criacao: new Date().getHours(),
  dia_semana: new Date().toLocaleDateString('pt-BR', { weekday: 'long' }),
  fonte_dados: 'orchestrator_tool_call',
  tool_original: input.source_tool,
  args_originais_presentes: !!input.tool_arguments
};

return {
  report_id: report.id,
  report_type: 'urban',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    severity,
    validated_category: validatedCategory,
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Agente de Análise de Relatos de Transporte
// Usa tool_arguments para acessar dados originais inferidos pelo LLM

const input = $input.first().json;
const report = input.report;
const toolArgs = input.tool_arguments || {};

// Descrição original do LLM
const description = (toolArgs.description || report.description || '').toLowerCase();

let priority = 'normal';
let severity = 'media';
let tags = [];

// Detecção de problemas críticos de transporte
const criticalKeywords = ['acidente', 'atropelamento', 'colisão', 'quebrado', 'parado', 'incêndio', 'descarrilou'];
const highKeywords = ['lotado', 'superlotado', 'atraso', 'não passou', 'cancelado', 'sem ar', 'porta aberta'];

if (criticalKeywords.some(k => description.includes(k))) {
  priority = 'urgente';
  severity = 'critica';
  tags.push('INCIDENTE_CRITICO');
} else if (highKeywords.some(k => description.includes(k))) {
  priority = 'alta';
  severity = 'alta';
  tags.push('PROBLEMA_OPERACIONAL');
}

// Classificação por tipo de problema
const problemTypes = {
  'atraso': 'ATRASO',
  'lotado': 'SUPERLOTACAO',
  'superlotado': 'SUPERLOTACAO',
  'ar condicionado': 'CLIMATIZACAO',
  'sem ar': 'CLIMATIZACAO',
  'limpeza': 'HIGIENE',
  'sujo': 'HIGIENE',
  'motorista': 'CONDUTA',
  'cobrador': 'CONDUTA',
  'acessibilidade': 'ACESSIBILIDADE',
  'cadeirante': 'ACESSIBILIDADE',
  'segurança': 'SEGURANCA',
  'assalto': 'SEGURANCA'
};

for (const [keyword, tag] of Object.entries(problemTypes)) {
  if (description.includes(keyword)) {
    tags.push(tag);
  }
}

// Análise temporal do horário da ocorrência
const occurrenceTime = toolArgs.occurrence_time || report.occurrence_time;
const hora = parseInt(occurrenceTime?.split(':')[0] || '12');
if (hora >= 6 && hora <= 9) tags.push('HORARIO_PICO_MANHA');
else if (hora >= 17 && hora <= 20) tags.push('HORARIO_PICO_TARDE');

const enrichedData = {
  linha_codigo: toolArgs.line_code || report.line_code_custom || null,
  horario_ocorrencia: occurrenceTime,
  data_ocorrencia: toolArgs.occurrence_date || report.occurrence_date,
  horario_pico: (hora >= 6 && hora <= 9) || (hora >= 17 && hora <= 20),
  impacto_relatado: toolArgs.impact_description || report.impact_description || null,
  fonte_dados: 'orchestrator_tool_call',
  tool_original: input.source_tool
};

return {
  report_id: report.id,
  report_type: 'transport',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    severity,
    validated_category: toolArgs.report_type || report.report_type,
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Agente de Análise de Avaliações de Serviço
// Usa tool_arguments para acessar dados originais inferidos pelo LLM

const input = $input.first().json;
const report = input.report;
const toolArgs = input.tool_arguments || {};

let priority = 'normal';
let severity = 'media';
let tags = [];

// Rating original inferido pelo LLM
const rating = toolArgs.rating_stars || report.rating_stars || 3;
if (rating <= 2) {
  priority = 'alta';
  severity = 'alta';
  tags.push('AVALIACAO_NEGATIVA');
} else if (rating >= 4) {
  tags.push('AVALIACAO_POSITIVA');
}

// Análise do texto da avaliação
const text = (toolArgs.rating_text || report.rating_text || '').toLowerCase();
const negativeKeywords = ['péssimo', 'horrível', 'demora', 'descaso', 'falta', 'nunca', 'abandonado', 'negligência'];
const positiveKeywords = ['excelente', 'ótimo', 'rápido', 'atencioso', 'eficiente', 'parabéns', 'recomendo'];

if (negativeKeywords.some(k => text.includes(k))) {
  priority = 'alta';
  severity = 'alta';
  tags.push('FEEDBACK_CRITICO');
}
if (positiveKeywords.some(k => text.includes(k))) {
  tags.push('FEEDBACK_ELOGIO');
}

// Sentimento original inferido pelo LLM
const sentimentFromLLM = toolArgs.sentiment || report.sentiment;

const enrichedData = {
  servico_tipo: toolArgs.service_type || report.service_type,
  servico_nome: toolArgs.service_name || report.service_name,
  rating_numerico: rating,
  tem_comentario: !!(toolArgs.rating_text || report.rating_text),
  sentimento_llm: sentimentFromLLM,
  sentimento_analise: rating <= 2 ? 'negativo' : rating >= 4 ? 'positivo' : 'neutro',
  fonte_dados: 'orchestrator_tool_call',
  tool_original: input.source_tool
};

return {
  report_id: report.id,
  report_type: 'service_rating',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    severity,
    validated_category: 'avaliacao_servico',
    tags,
    enriched_data: enrichedData,
    workflow_id: $workflow.id
  }
};

// Fallback para eventos sem source_tool (compatibilidade legada)
const input = $input.first().json;
const event = input.event;

let priority = 'normal';
let tags = ['LEGACY_EVENT'];

return {
  report_id: input.report?.id,
  report_type: input.report?.type || 'unknown',
  callback_url: input.callback_url,
  secret_key: input.secret_key,
  processed_data: {
    priority,
    validated_category: 'nao_classificado',
    tags,
    enriched_data: { evento_original: event },
    workflow_id: $workflow.id
  }
};

// Log de sucesso
const response = $input.first().json;
console.log('Callback enviado com sucesso:', response);
return { success: true, response };
